export interface ButtonsProps {
  /**
   * Variant
   * Friendly names map to internal IDs:
   *   "Primary" → II8FlOncb
   *   "Secondary" → fQ0rqGoX0
   */
  variant?: 'Primary' | 'Secondary' | 'II8FlOncb' | 'fQ0rqGoX0';
  /**
   * Text — pass as `U7iesBhi6` not `text`.
   * @default "Check Work"
   */
  U7iesBhi6?: string;
  onU7iesBhi6Change?: string;
  /**
   * Link — pass as `Xide8dzh1` not `link`.
   */
  Xide8dzh1?: string;
  /** Additional properties */
  [key: string]: unknown;
}
